import{_ as r,o as e,c as a,a0 as o}from"./chunks/framework.Bmhw_dvp.js";const g=JSON.parse('{"title":"Skills & Tools","description":"","frontmatter":{},"headers":[],"relativePath":"aiAgents/skills.md","filePath":"aiAgents/skills.md"}'),l={name:"aiAgents/skills.md"};function i(s,t,h,n,u,c){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="skills-tools" tabindex="-1">Skills &amp; Tools <a class="header-anchor" href="#skills-tools" aria-label="Permalink to &quot;Skills &amp; Tools&quot;">​</a></h1><p>AI 生态中丰富的工具、插件和技能集，按类型分为 <strong>MCP 协议</strong>、<strong>浏览器自动化</strong>、<strong>代码助手</strong>、<strong>向量数据库</strong>和<strong>其他实用工具</strong>。</p><hr><h2 id="mcp-协议" tabindex="-1">MCP 协议 <a class="header-anchor" href="#mcp-协议" aria-label="Permalink to &quot;MCP 协议&quot;">​</a></h2><p>MCP（Model Context Protocol，模型上下文协议）是 Anthropic 推出的开放协议，用于标准化 AI 模型与外部数据源、工具之间的集成。</p><h3 id="官方资源" tabindex="-1">官方资源 <a class="header-anchor" href="#官方资源" aria-label="Permalink to &quot;官方资源&quot;">​</a></h3><ul><li><strong>MCP 官网</strong>：<a href="https://modelcontextprotocol.io" target="_blank" rel="noreferrer">https://modelcontextprotocol.io</a></li><li><strong>GitHub</strong>：<a href="https://github.com/modelcontextprotocol" target="_blank" rel="noreferrer">https://github.com/modelcontextprotocol</a></li><li><strong>规范文档</strong>：<a href="https://spec.modelcontextprotocol.io" target="_blank" rel="noreferrer">https://spec.modelcontextprotocol.io</a></li></ul><h3 id="常用-mcp-servers" tabindex="-1">常用 MCP Servers <a class="header-anchor" href="#常用-mcp-servers" aria-label="Permalink to &quot;常用 MCP Servers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>名称</th><th>功能</th><th>链接</th></tr></thead><tbody><tr><td>filesystem</td><td>本地文件系统访问</td><td><a href="https://github.com/modelcontextprotocol/servers/tree/main/src/filesystem" target="_blank" rel="noreferrer">GitHub</a></td></tr><tr><td>github</td><td>GitHub API 集成</td><td><a href="https://github.com/modelcontextprotocol/servers/tree/main/src/github" target="_blank" rel="noreferrer">GitHub</a></td></tr><tr><td>postgres</td><td>PostgreSQL 数据库访问</td><td><a href="https://github.com/modelcontextprotocol/servers/tree/main/src/postgres" target="_blank" rel="noreferrer">GitHub</a></td></tr><tr><td>slack</td><td>Slack 工作区集成</td><td><a href="https://github.com/modelcontextprotocol/servers/tree/main/src/slack" target="_blank" rel="noreferrer">GitHub</a></td></tr><tr><td>brave-search</td><td>Brave 搜索引擎</td><td><a href="https://github.com/modelcontextprotocol/servers/tree/main/src/brave-search" target="_blank" rel="noreferrer">GitHub</a></td></tr></tbody></table><hr><h2 id="浏览器自动化" tabindex="-1">浏览器自动化 <a class="header-anchor" href="#浏览器自动化" aria-label="Permalink to &quot;浏览器自动化&quot;">​</a></h2><h3 id="playwright" tabindex="-1">Playwright <a class="header-anchor" href="#playwright" aria-label="Permalink to &quot;Playwright&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://playwright.dev" target="_blank" rel="noreferrer">https://playwright.dev</a></li><li><strong>GitHub</strong>：<a href="https://github.com/microsoft/playwright" target="_blank" rel="noreferrer">https://github.com/microsoft/playwright</a></li></ul><p>微软开源的浏览器自动化工具，支持多浏览器、多语言，是 Agent 操作网页的首选工具。</p><hr><h3 id="puppeteer" tabindex="-1">Puppeteer <a class="header-anchor" href="#puppeteer" aria-label="Permalink to &quot;Puppeteer&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://pptr.dev" target="_blank" rel="noreferrer">https://pptr.dev</a></li><li><strong>GitHub</strong>：<a href="https://github.com/puppeteer/puppeteer" target="_blank" rel="noreferrer">https://github.com/puppeteer/puppeteer</a></li></ul><p>Google 开源的 Node.js 浏览器控制库，适合需要与 Chrome DevTools Protocol 深度集成的场景。</p><hr><h3 id="browser-use" tabindex="-1">Browser-use <a class="header-anchor" href="#browser-use" aria-label="Permalink to &quot;Browser-use&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://browser-use.com" target="_blank" rel="noreferrer">https://browser-use.com</a></li><li><strong>GitHub</strong>：<a href="https://github.com/browser-use/browser-use" target="_blank" rel="noreferrer">https://github.com/browser-use/browser-use</a></li></ul><p>专为 AI Agent 设计的浏览器自动化库，让大模型能够像人类一样浏览和操作网页。</p><hr><h3 id="stagehand" tabindex="-1">Stagehand <a class="header-anchor" href="#stagehand" aria-label="Permalink to &quot;Stagehand&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://stagehand.dev" target="_blank" rel="noreferrer">https://stagehand.dev</a></li><li><strong>GitHub</strong>：<a href="https://github.com/browserbase/stagehand" target="_blank" rel="noreferrer">https://github.com/browserbase/stagehand</a></li></ul><p>基于 Playwright 的 AI 浏览器自动化框架，支持自然语言驱动的网页操作。</p><hr><h2 id="代码助手" tabindex="-1">代码助手 <a class="header-anchor" href="#代码助手" aria-label="Permalink to &quot;代码助手&quot;">​</a></h2><h3 id="github-copilot" tabindex="-1">GitHub Copilot <a class="header-anchor" href="#github-copilot" aria-label="Permalink to &quot;GitHub Copilot&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://github.com/features/copilot" target="_blank" rel="noreferrer">https://github.com/features/copilot</a></li></ul><p>GitHub 与 OpenAI 合作推出的 AI 编程助手，支持代码补全、聊天和命令行工具。</p><hr><h3 id="cursor" tabindex="-1">Cursor <a class="header-anchor" href="#cursor" aria-label="Permalink to &quot;Cursor&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://www.cursor.com" target="_blank" rel="noreferrer">https://www.cursor.com</a></li></ul><p>基于 VS Code 的 AI 原生编辑器，内置 Claude、GPT-4 等模型，支持代码生成、重构和问答。</p><hr><h3 id="trae" tabindex="-1">Trae <a class="header-anchor" href="#trae" aria-label="Permalink to &quot;Trae&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://www.trae.ai" target="_blank" rel="noreferrer">https://www.trae.ai</a></li><li><strong>国内版</strong>：<a href="https://www.trae.com.cn" target="_blank" rel="noreferrer">https://www.trae.com.cn</a></li></ul><p>字节跳动推出的 AI 原生 IDE，基于 Claude 3.5 等模型，提供 Builder 模式和深度代码理解。</p><hr><h3 id="windsurf" tabindex="-1">Windsurf <a class="header-anchor" href="#windsurf" aria-label="Permalink to &quot;Windsurf&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://codeium.com/windsurf" target="_blank" rel="noreferrer">https://codeium.com/windsurf</a></li></ul><p>Codeium 推出的 AI 编辑器，支持 Cascade 工作流，可同时编辑多个文件。</p><hr><h3 id="continue" tabindex="-1">Continue <a class="header-anchor" href="#continue" aria-label="Permalink to &quot;Continue&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://www.continue.dev" target="_blank" rel="noreferrer">https://www.continue.dev</a></li><li><strong>GitHub</strong>：<a href="https://github.com/continuedev/continue" target="_blank" rel="noreferrer">https://github.com/continuedev/continue</a></li></ul><p>开源的 AI 代码助手插件，支持 VS Code 和 JetBrains，可连接任意模型和 API。</p><hr><h2 id="向量数据库" tabindex="-1">向量数据库 <a class="header-anchor" href="#向量数据库" aria-label="Permalink to &quot;向量数据库&quot;">​</a></h2><h3 id="pinecone" tabindex="-1">Pinecone <a class="header-anchor" href="#pinecone" aria-label="Permalink to &quot;Pinecone&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://www.pinecone.io" target="_blank" rel="noreferrer">https://www.pinecone.io</a></li></ul><p>托管式向量数据库服务，专为高性能相似性搜索设计。</p><hr><h3 id="milvus-zilliz" tabindex="-1">Milvus / Zilliz <a class="header-anchor" href="#milvus-zilliz" aria-label="Permalink to &quot;Milvus / Zilliz&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://milvus.io" target="_blank" rel="noreferrer">https://milvus.io</a></li><li><strong>GitHub</strong>：<a href="https://github.com/milvus-io/milvus" target="_blank" rel="noreferrer">https://github.com/milvus-io/milvus</a></li></ul><p>开源分布式向量数据库，由 Zilliz 公司维护，支持十亿级向量检索。</p><hr><h3 id="chroma" tabindex="-1">Chroma <a class="header-anchor" href="#chroma" aria-label="Permalink to &quot;Chroma&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://www.trychroma.com" target="_blank" rel="noreferrer">https://www.trychroma.com</a></li><li><strong>GitHub</strong>：<a href="https://github.com/chroma-core/chroma" target="_blank" rel="noreferrer">https://github.com/chroma-core/chroma</a></li></ul><p>开源嵌入式向量数据库，以简单易用著称，适合快速原型开发。</p><hr><h3 id="weaviate" tabindex="-1">Weaviate <a class="header-anchor" href="#weaviate" aria-label="Permalink to &quot;Weaviate&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://weaviate.io" target="_blank" rel="noreferrer">https://weaviate.io</a></li><li><strong>GitHub</strong>：<a href="https://github.com/weaviate/weaviate" target="_blank" rel="noreferrer">https://github.com/weaviate/weaviate</a></li></ul><p>开源向量搜索引擎，支持 GraphQL 接口和模块化 AI 集成。</p><hr><h2 id="其他实用工具" tabindex="-1">其他实用工具 <a class="header-anchor" href="#其他实用工具" aria-label="Permalink to &quot;其他实用工具&quot;">​</a></h2><h3 id="comfyui" tabindex="-1">ComfyUI <a class="header-anchor" href="#comfyui" aria-label="Permalink to &quot;ComfyUI&quot;">​</a></h3><ul><li><strong>GitHub</strong>：<a href="https://github.com/comfyanonymous/ComfyUI" target="_blank" rel="noreferrer">https://github.com/comfyanonymous/ComfyUI</a></li></ul><p>基于节点的 Stable Diffusion 图形化界面，广泛用于 AI 图像生成工作流。</p><hr><h3 id="ollama" tabindex="-1">Ollama <a class="header-anchor" href="#ollama" aria-label="Permalink to &quot;Ollama&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://ollama.com" target="_blank" rel="noreferrer">https://ollama.com</a></li><li><strong>GitHub</strong>：<a href="https://github.com/ollama/ollama" target="_blank" rel="noreferrer">https://github.com/ollama/ollama</a></li></ul><p>在本地运行大语言模型的工具，一行命令即可启动 Llama、Qwen、Mistral 等模型。</p><hr><h3 id="vllm" tabindex="-1">vLLM <a class="header-anchor" href="#vllm" aria-label="Permalink to &quot;vLLM&quot;">​</a></h3><ul><li><strong>GitHub</strong>：<a href="https://github.com/vllm-project/vllm" target="_blank" rel="noreferrer">https://github.com/vllm-project/vllm</a></li></ul><p>高性能大模型推理引擎，采用 PagedAttention 技术，吞吐量远超传统方案。</p><hr><h3 id="litellm" tabindex="-1">LiteLLM <a class="header-anchor" href="#litellm" aria-label="Permalink to &quot;LiteLLM&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://www.litellm.ai" target="_blank" rel="noreferrer">https://www.litellm.ai</a></li><li><strong>GitHub</strong>：<a href="https://github.com/BerriAI/litellm" target="_blank" rel="noreferrer">https://github.com/BerriAI/litellm</a></li></ul><p>统一的多模型 API 网关，支持 100+ LLM 的统一定价、路由和监控。</p><hr><h3 id="unstructured" tabindex="-1">Unstructured <a class="header-anchor" href="#unstructured" aria-label="Permalink to &quot;Unstructured&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://unstructured.io" target="_blank" rel="noreferrer">https://unstructured.io</a></li><li><strong>GitHub</strong>：<a href="https://github.com/Unstructured-IO/unstructured" target="_blank" rel="noreferrer">https://github.com/Unstructured-IO/unstructured</a></li></ul><p>开源的文档解析和预处理库，支持 PDF、Word、HTML 等多种格式转换为结构化数据。</p><hr><h3 id="prompt-flow" tabindex="-1">Prompt flow <a class="header-anchor" href="#prompt-flow" aria-label="Permalink to &quot;Prompt flow&quot;">​</a></h3><ul><li><strong>文档</strong>：<a href="https://microsoft.github.io/promptflow" target="_blank" rel="noreferrer">https://microsoft.github.io/promptflow</a></li><li><strong>GitHub</strong>：<a href="https://github.com/microsoft/promptflow" target="_blank" rel="noreferrer">https://github.com/microsoft/promptflow</a></li></ul><p>微软开源的 LLM 应用开发工具，支持提示词管理、评估和流程编排。</p>',89)])])}const d=r(l,[["render",i]]);export{g as __pageData,d as default};
